// n8n Code node
// Recomendado: Run Once for All Items = true
// Entrada: items = [{json:{document:{pageContent, metadata:{metadata:{...}}}, score}}, ...]
// Saída: 1 item por CRUZEIRO (slug), com cabins[] e attractions[] completos

function localTodayIso() {
  const now = new Date();
  const local = new Date(now.getTime() - now.getTimezoneOffset() * 60000);
  return local.toISOString().slice(0, 10);
}

function getDoc(item) {
  return item?.json?.document ?? {};
}

function getMeta(item) {
  const doc = getDoc(item);
  return doc?.metadata?.metadata ?? {};
}

function getPageContent(item) {
  const doc = getDoc(item);
  return doc?.pageContent ?? '';
}

function normalizeCabinType(c) {
  if (!c) return null;
  const v = String(c).toLowerCase();
  if (v === 'yacht_club' || v === 'yacht club') return 'yacht_club';
  if (['suite', 'suíte'].includes(v)) return 'suite';
  if (['varanda', 'sacada', 'balcão', 'balcao'].includes(v)) return 'varanda';
  if (['externa', 'janela', 'vista mar', 'vista-mar'].includes(v)) return 'externa';
  if (['interna', 'standard'].includes(v)) return 'interna';
  return v;
}

const todayIso = localTodayIso();

// 1) Normaliza e filtra por data
const rows = items
  .map(item => {
    const meta = getMeta(item);
    const pageContent = getPageContent(item);
    const score = item?.json?.score ?? null;

    const departureDate = meta?.departure_date ?? null;
    if (departureDate && departureDate < todayIso) return null;

    const slug = meta?.slug ?? null;
    if (!slug) return null;

    const sourcePreview = pageContent.length > 320 ? pageContent.slice(0, 320) + '...' : pageContent;

    return {
      slug,
      score: score !== null ? Number(score) : null,

      // Campos de cruzeiro
      cruise_name: meta?.cruise_name ?? null,
      display_name: meta?.display_name ?? null,
      ship: meta?.ship ?? null,
      theme: meta?.theme ?? null,

      departure_date: meta?.departure_date ?? null,
      return_date: meta?.return_date ?? null,
      date_nights: meta?.date_nights ?? null,
      nights: meta?.nights ?? null,

      embark: meta?.embark ?? null,
      embark_state: meta?.embark_state ?? null,
      embark_country: meta?.embark_country ?? null,

      // Listas
      headliners: Array.isArray(meta?.headliners) ? meta.headliners : [],
      attractions: Array.isArray(meta?.attractions) ? meta.attractions : [],
      normalized_artists: Array.isArray(meta?.normalized_artists) ? meta.normalized_artists : [],
      search_keywords: Array.isArray(meta?.search_keywords) ? meta.search_keywords : [],

      // Cabin info (cada doc = uma experience resource)
      cabin: {
        cabin_type: normalizeCabinType(meta?.cabin_type ?? null),
        cabin_display: meta?.cabin_display ?? null,
        occupancy: meta?.occupancy ?? null,

        currency: 'BRL',
        price_pp_brl: meta?.price_pp_brl ?? null,
        price_cabin_total_brl: meta?.price_cabin_total_brl ?? null,
        price_per_night: meta?.price_per_night ?? null,
        port_fee_per_person: meta?.port_fee_per_person ?? null,
        fees_included: meta?.fees_included ?? null,
        price_bucket: meta?.price_bucket ?? null,

        source_preview: sourcePreview,
        score: score !== null ? Number(score) : null,
      },
    };
  })
  .filter(Boolean);

// 2) Agrupa por slug (um item por cruzeiro)
const bySlug = new Map();

for (const r of rows) {
  const g = bySlug.get(r.slug);
  if (!g) {
    bySlug.set(r.slug, {
      slug: r.slug,
      cruise_name: r.cruise_name,
      display_name: r.display_name,
      ship: r.ship,
      theme: r.theme,

      departure_date: r.departure_date,
      return_date: r.return_date,
      date_nights: r.date_nights,
      nights: r.nights,

      embark: r.embark,
      embark_state: r.embark_state,
      embark_country: r.embark_country,

      currency: 'BRL',

      // listas agregadas (dedupe)
      headliners: new Set(r.headliners),
      attractions: new Set(r.attractions),
      normalized_artists: new Set(r.normalized_artists),
      search_keywords: new Set(r.search_keywords),

      // experience resource
      cabins: [],
      // score agregado (maior)
      best_score: r.score ?? null,
    });
  }

  const group = bySlug.get(r.slug);

  // agrega sets
  r.headliners.forEach(x => group.headliners.add(x));
  r.attractions.forEach(x => group.attractions.add(x));
  r.normalized_artists.forEach(x => group.normalized_artists.add(x));
  r.search_keywords.forEach(x => group.search_keywords.add(x));

  // adiciona experience resource (dedupe por chave)
  const key = JSON.stringify([
    r.cabin.cabin_type,
    r.cabin.occupancy,
    r.cabin.price_pp_brl,
    r.cabin.price_cabin_total_brl,
  ]);

  if (!group._cabinKeys) group._cabinKeys = new Set();
  if (!group._cabinKeys.has(key)) {
    group._cabinKeys.add(key);
    group.cabins.push(r.cabin);
  }

  // melhor score
  const bs = group.best_score ?? -1;
  const cs = r.score ?? -1;
  if (cs > bs) group.best_score = cs;
}

// 3) Finaliza arrays + ordena experience resource por preço
const result = Array.from(bySlug.values()).map(g => {
  const cabins = g.cabins.slice().sort((a, b) => {
    const pa = a.price_pp_brl ?? Number.POSITIVE_INFINITY;
    const pb = b.price_pp_brl ?? Number.POSITIVE_INFINITY;
    return pa - pb;
  });

  return {
    slug: g.slug,
    cruise_name: g.cruise_name,
    display_name: g.display_name,
    ship: g.cruise_name,
    theme: g.theme,

    departure_date: g.departure_date,
    return_date: g.return_date,
    date_nights: g.date_nights,
    nights: g.nights,

    embark: g.embark,
    embark_state: g.embark_state,
    embark_country: g.embark_country,

    currency: 'BRL',

    headliners: Array.from(g.headliners),
    attractions: Array.from(g.attractions),
    normalized_artists: Array.from(g.normalized_artists),
    search_keywords: Array.from(g.search_keywords),

    best_score: g.best_score ?? null,
    cabins,
  };
});

// 4) Ordena cruzeiros por best_score desc
//result.sort((a, b) => (b.best_score ?? -1) - (a.best_score ?? -1));

// 5) Se você quiser retornar APENAS o cruzeiro mais relevante (ex. "o navio da 89")
// descomente:
// return [{ json: result[0] ?? null }];

return result.map(r => ({ json: r }));
